    public int minInsertions(String s) {
        int balance = 0;
        int insertions = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                balance += 2;
            } else {
                balance--;
            }
            if (balance < 0) {
                insertions++;
                balance += 2;
            }
        }
        insertions += balance;
        return insertions;
    }
